waves.frame_eqs_str:
h=q5;
s = 0.8;
l= 0.5;
///////////////////////////////////////////////////////////////////////////////////////////////
//
//                            HSL to RGB by PieturP
//
// hue         h ( 0 - 0.9 )                          rr ( 0 - 1 )
// saturation  s ( 0 - 1 )            - >             gg ( 0 - 1 )
// luminance   l ( 0 - 1 )                            bb ( 0 - 1 )
//
cc=(6*h);
cc=if(below(cc,1),0,if(below(cc,2),1,if(below(cc,3),2,if(below(cc,4),3,if(below(cc,5),4,5)))));
zf=(6*h)-cc;
zm=l;
zp=l*(1-s);
zq=l*(1-s*zf);
zt=l*(1-s*(1-zf));
monitor=zq;
rr=if(equal(cc,0),zm,if(equal(cc,1),zq,if(equal(cc,2),zp,if(equal(cc,3),zp,if(equal(cc,4),zt,zm)))));
gg=if(equal(cc,0),zt,if(equal(cc,1),zm,if(equal(cc,2),zm,if(equal(cc,3),zq,if(equal(cc,4),zp,zp)))));
bb=if(equal(cc,0),zp,if(equal(cc,1),zp,if(equal(cc,2),zt,if(equal(cc,3),zm,if(equal(cc,4),zm,zq)))));
rr=if(equal(s,0),l,rr);
gg=if(equal(s,0),l,gg);
bb=if(equal(s,0),l,bb);

///////////////////////////////////////////////////////////////////////////////////////////////
r=rr;
g=gg;
b=bb;

waves.point_eqs_str:
n=sample*6.283;
phs=-sample * 0.4 ;
tm=q4 + phs*2 - 0.02;

flip=flip+1;
flip=flip*below(flip,2);

xp=0;
yp=(flip*0.4-0.2)*(sample);
zp=0;

//spin;
ang=tm*23 + sin(tm*76 + time*4)*0.3;;
sa=sin(ang);ca=cos(ang);
xr=xp*sa + yp*ca;
yr=xp*ca - yp*sa;
zr=zp;

xp=xr;
yp=yr + 0.05 + (sin(tm)*0.5 + 0.5)*0.2 + 0.05;
zp=zr;

//wrist movement;
ang=0.5*(sin(tm*2)+sin(tm*1.248));

xq=xp;
sa=sin(ang);ca=cos(ang);
yq=yp*sa + zp*ca;
zq=yp*ca - zp*sa;


ang=tm*8;
sa=sin(ang);ca=cos(ang);
xp=xq*sa + yq*ca;
yp=xq*ca - yq*sa;
zp=zq;

//forearm movement;
zp=zp-0.3;
ang=3.14 + (sin(tm*2 - 0.5)+sin(tm*1.237))*1.25;
xq=xp;
sa=sin(ang);ca=cos(ang);
yq=yp*sa + zp*ca;
zq=yp*ca - zp*sa;

//upper arm twist
ang=-1.0 + 0.5*(cos(tm*3 + 0.5)+cos(tm*0.867));
xp=xq*sa + yq*ca;
yp=xq*ca - yq*sa;
zp=zq;

//upper arm outward;
zp=zp-0.35;
ang=(cos(tm*1)+cos(tm*0.653))*0.875 - 1.05;
sa=sin(ang);ca=cos(ang);
xq=xp*sa + zp*ca;
yq=yp;
zq=xp*ca - zp*sa;

//upper arm up down;
ang=0.5*(cos(tm*1.273)+cos(tm));
xp=xq;
sa=sin(ang);ca=cos(ang);
yp=yq*ca - zq*sa;
zp=yq*sa + zq*ca;

//xp=xq;yp=yq;zp=zq;


//project into screenspace and draw on screen
zp=zp+1.5;
xs=xp/zp;
ys=yp/zp;

x=xs+0.5;
y=ys*1.3+0.5;


a=(1-sample);

s=sample*6.28;

//plot random x position via function of sample pos;
xp=sin(s)+sin(s*0.44)+sin(s*14.3)+sin(s*12.8);
xp=xp*0.20;

//plot random y position via function of sample pos;
yp=cos(s)+sin(s*0.29)+cos(s*19.4)+sin(s*37.7);
yp=yp*0.20;

//plot random z position via function of sample pos;
zp=cos(s)+cos(s*6.24)+cos(s*37.4)+cos(s*29.7);
zp=zp*0.25;

//pull stars toward screen
zp=zp + 1 - t1;

//correct when below 0
zp=if( below(zp,0) , zp+2 , zp );

//darken far stars
a=(1 - zp*0.5);

zp=zp*0.7;

x_screen=xp/zp + 0.5;
y_screen=yp/zp + 0.5;

x=x_screen;
y=y_screen;

r=0;
g=0;
b=0;

comp:
shader_body { 
 vec2 uv_1;
 vec3 ret_2;
 uv_1 = (0.05 + (0.9 * uv));
 ret_2 = (abs((
   ((texture (sampler_blur3, uv_1).xyz * scale3) + bias3)
  - texture (sampler_main, uv_1).xyz)) * 6.0);
 ret_2 = (ret_2 * 1.333);
 vec4 tmpvar_3;
 tmpvar_3.w = 1.0;
 tmpvar_3.xyz = ret_2;
 ret = tmpvar_3.xyz;
}
